import{_ as e,c as s,o,ag as d}from"./chunks/framework.S-Qvb3wi.js";const u=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"daily/nodejs.md","filePath":"daily/nodejs.md"}'),t={name:"daily/nodejs.md"};function l(i,a,r,n,c,m){return o(),s("div",null,a[0]||(a[0]=[d('<h2 id="谈谈你对nodejs的理解" tabindex="-1">谈谈你对nodejs的理解 <a class="header-anchor" href="#谈谈你对nodejs的理解" aria-label="Permalink to &quot;谈谈你对nodejs的理解&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><p>Node.js 是一个开源的、跨平台的运行时环境，能够使JavaScript在服务器端运行。</p><ul><li>事件驱动和非阻塞 I/O：Node.js 使用事件驱动的架构，采用单线程模型，通过事件循环机制处理并发请求。这使得它在处理 I/O 密集型任务（如网络请求、文件读写）时非常高效，因为不会因为某个操作的等待而阻塞整个进程。</li><li>V8 引擎：Node.js 基于 Chrome 的 V8 JavaScript 引擎构建。V8 引擎将 JavaScript 编译为高效的机器代码，这使得 Node.js 能够以极快的速度执行 JavaScript 代码。</li><li>npm: 包管理器</li></ul></details><h2 id="nodejs-如何克服-i-o-操作阻塞的问题" tabindex="-1">nodejs 如何克服 I/O 操作阻塞的问题 <a class="header-anchor" href="#nodejs-如何克服-i-o-操作阻塞的问题" aria-label="Permalink to &quot;nodejs 如何克服 I/O 操作阻塞的问题&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><ul><li>Node.js 使用单线程事件循环（Event Loop）来处理所有的 I/O 操作。事件循环负责监听和分发事件，确保 Node.js 可以在等待 I/O 操作（如文件读写、网络请求）完成时继续处理其他任务。</li><li>当一个 I/O 操作（如读取文件）发起时，Node.js 不会等待操作完成，而是将其发送到操作系统，然后继续处理其他任务。当操作系统完成 I/O 操作时，它会将结果返回给 Node.js，Node.js 再将其分发到相应的回调函数。</li></ul></details><h2 id="nodejs是单线程的吗-它是如何处理并发的" tabindex="-1">nodejs是单线程的吗？它是如何处理并发的？ <a class="header-anchor" href="#nodejs是单线程的吗-它是如何处理并发的" aria-label="Permalink to &quot;nodejs是单线程的吗？它是如何处理并发的？&quot;">​</a></h2><details class="details custom-block"><summary>查看详情</summary><p>Node.js 在其主要的 JavaScript 执行环境中是单线程的，但它通过一些独特的机制来高效处理并发操作。这些机制包括事件循环、非阻塞 I/O 和多线程技术的辅助。</p></details>',6)]))}const p=e(t,[["render",l]]);export{u as __pageData,p as default};
